UPDATE sentences SET
  ex1 = 'There''s a severe weather warning in place for the northern regions.', ex1_ko = '북부 지역에 악기상 경보가 발령되어 있어요.',
  ex2 = 'There''s a flood warning in place for the coastal areas east of the city.', ex2_ko = '도시 동쪽 해안 지역에 홍수 경보가 발령되어 있어요.',
  ex3 = 'There''s a frost warning in place for elevated areas above 400 metres tonight.', ex3_ko = '오늘 밤 해발 400미터 이상의 고지대에 서리 경보가 발령되어 있어요.',
  ex4 = 'There''s a high wind advisory in place for all exposed hilltops and coastal roads.', ex4_ko = '모든 노출된 언덕 정상과 해안 도로에 강풍 주의보가 발령되어 있어요.',
  ex5 = 'There''s a heat advisory in place urging people to avoid strenuous outdoor activity between noon and four.', ex5_ko = '정오부터 4시 사이에 격렬한 야외 활동을 자제하도록 촉구하는 폭염 주의보가 발령되어 있어요.'
