UPDATE sentences SET
  ex1 = 'With the heat index above 40 degrees, outdoor activities are not advisable.', ex1_ko = '열지수가 40도를 넘으면서 야외 활동은 권장하지 않아요.',
  ex2 = 'With the UV index above 8, sun protection is strongly advisable throughout the day.', ex2_ko = '자외선 지수가 8을 넘으면서 하루 종일 자외선 차단이 강력히 권고돼요.',
  ex3 = 'With the wind speed exceeding 80 kilometres per hour, driving on exposed roads is not advisable.', ex3_ko = '풍속이 시속 80킬로미터를 초과하면서 노출된 도로 운전은 권장하지 않아요.',
  ex4 = 'With the visibility below 50 metres, operating heavy machinery outdoors is not advisable.', ex4_ko = '시야가 50미터 이하로 떨어지면서 야외에서 중장비 운전은 권장하지 않아요.',
  ex5 = 'With the air quality index in the hazardous range, prolonged outdoor exercise is not advisable today.', ex5_ko = '공기 질 지수가 위험 범위에 있으면서 오늘 장시간 야외 운동은 권장하지 않아요.'
WHERE id = 's_weather_B1_07';

UPDATE sentences SET
  ex1 = 'Climate change is intensifying the frequency and severity of extreme weather events.', ex1_ko = '기후 변화가 극단적인 기상 현상의 빈도와 심각도를 강화하고 있어요.',
  ex2 = 'Climate change is accelerating the melting of glaciers and polar ice sheets worldwide.', ex2_ko = '기후 변화가 전 세계적으로 빙하와 극지방 빙상의 용해를 가속화하고 있어요.',
  ex3 = 'Climate change is disrupting the agricultural calendars of farmers across the tropics.', ex3_ko = '기후 변화가 열대 지역 전역에 걸쳐 농부들의 농업 달력을 교란시키고 있어요.',
  ex4 = 'Climate change is shifting the ranges of plant and animal species toward the poles and to higher altitudes.', ex4_ko = '기후 변화가 동식물 종의 서식 범위를 극지방과 더 높은 고도 쪽으로 이동시키고 있어요.',
  ex5 = 'Climate change is exacerbating water stress in already drought-prone regions of the world.', ex5_ko = '기후 변화가 이미 가뭄에 취약한 세계 지역에서 물 부족 문제를 악화시키고 있어요.'
WHERE id = 's_weather_B2_01';

UPDATE sentences SET
  ex1 = 'The monsoon season has become increasingly unpredictable due to shifting weather patterns.', ex1_ko = '변화하는 기상 패턴으로 인해 몬순 시즌이 점점 예측하기 어려워지고 있어요.',
  ex2 = 'The growing season has become increasingly shorter due to late frosts and unpredictable spring weather.', ex2_ko = '늦은 서리와 예측할 수 없는 봄 날씨로 인해 성장 계절이 점점 짧아지고 있어요.',
  ex3 = 'The wildfire season has become increasingly prolonged due to hotter and drier summer conditions.', ex3_ko = '더 덥고 건조한 여름 상태로 인해 산불 시즌이 점점 길어지고 있어요.',
  ex4 = 'The typhoon season has become increasingly volatile due to warmer ocean surface temperatures.', ex4_ko = '더 따뜻한 해수면 온도로 인해 태풍 시즌이 점점 변동성이 커지고 있어요.',
  ex5 = 'The snowpack in mountain regions has become increasingly unreliable due to rising winter temperatures.', ex5_ko = '겨울 기온 상승으로 인해 산악 지역의 적설량이 점점 신뢰할 수 없게 되고 있어요.'
WHERE id = 's_weather_B2_02';

UPDATE sentences SET
  ex1 = 'There is growing scientific consensus that anthropogenic emissions are driving global warming.', ex1_ko = '인위적 배출이 지구 온난화를 유발하고 있다는 과학적 공감대가 커지고 있어요.',
  ex2 = 'There is growing public awareness that individual actions can make a meaningful difference to carbon emissions.', ex2_ko = '개인의 행동이 탄소 배출에 의미 있는 차이를 만들 수 있다는 대중의 인식이 커지고 있어요.',
  ex3 = 'There is growing international pressure that wealthy nations must do more to fund climate adaptation in the Global South.', ex3_ko = '부유한 국가들이 글로벌 사우스의 기후 적응을 지원하기 위해 더 많이 해야 한다는 국제적 압력이 커지고 있어요.',
  ex4 = 'There is growing evidence that feedback loops in the climate system are stronger than early models suggested.', ex4_ko = '기후 시스템의 피드백 루프가 초기 모델이 시사한 것보다 더 강하다는 증거가 늘고 있어요.',
  ex5 = 'There is growing concern that current pledges under the Paris Agreement are insufficient to limit warming to 1.5 degrees.', ex5_ko = '파리 협정에 따른 현재 약속이 온난화를 1.5도로 제한하기에 충분하지 않다는 우려가 커지고 있어요.'
WHERE id = 's_weather_B2_03';

UPDATE sentences SET
  ex1 = 'The correlation between rising CO₂ levels and global average temperatures is well established.', ex1_ko = 'CO₂ 농도 상승과 지구 평균 기온 사이의 상관관계는 잘 확립되어 있어요.',
  ex2 = 'The correlation between deforestation rates and local rainfall decline is well documented in the scientific literature.', ex2_ko = '삼림 벌채율과 지역 강수량 감소 사이의 상관관계는 과학 문헌에 잘 기록되어 있어요.',
  ex3 = 'The correlation between Arctic sea ice loss and extreme mid-latitude winter weather is an active area of research.', ex3_ko = '북극 해빙 손실과 중위도 극한 겨울 날씨 사이의 상관관계는 활발한 연구 분야예요.',
  ex4 = 'The correlation between urban heat island intensity and impervious surface coverage is remarkably consistent across cities.', ex4_ko = '도시 열섬 강도와 불침투성 지표면 덮개 사이의 상관관계가 도시 전반에 걸쳐 놀랍도록 일관해요.',
  ex5 = 'The correlation between stratospheric aerosol loading from volcanic eruptions and short-term global cooling is clearly evident in the temperature record.', ex5_ko = '화산 폭발로 인한 성층권 에어로졸 부하와 단기 지구 냉각 사이의 상관관계가 기온 기록에서 명확히 나타나요.'
WHERE id = 's_weather_B2_04';

UPDATE sentences SET
  ex1 = 'Prolonged droughts in sub-Saharan Africa are threatening food security for millions.', ex1_ko = '사하라 이남 아프리카의 장기 가뭄이 수백만 명의 식량 안보를 위협하고 있어요.',
  ex2 = 'Prolonged heatwaves in South Asia are threatening the livelihoods of outdoor workers during summer months.', ex2_ko = '남아시아의 장기 폭염이 여름철 야외 노동자들의 생계를 위협하고 있어요.',
  ex3 = 'Prolonged flooding in low-lying river deltas is threatening the homes and farmland of tens of millions.', ex3_ko = '저지대 강 삼각주의 장기 홍수가 수천만 명의 주거지와 농지를 위협하고 있어요.',
  ex4 = 'Prolonged ice loss in mountain glaciers is threatening the freshwater supplies of cities downstream.', ex4_ko = '산악 빙하의 장기 빙하 손실이 하류 도시들의 담수 공급을 위협하고 있어요.',
  ex5 = 'Prolonged coral bleaching events are threatening the biodiversity and fisheries of tropical reef ecosystems.', ex5_ko = '장기 산호 백화 현상이 열대 암초 생태계의 생물 다양성과 어업을 위협하고 있어요.'
WHERE id = 's_weather_B2_05';

UPDATE sentences SET
  ex1 = 'Rising sea levels pose an existential threat to low-lying island nations.', ex1_ko = '해수면 상승이 저지대 도서 국가들에 실존적 위협이 되고 있어요.',
  ex2 = 'Accelerating permafrost thaw poses a significant threat to Arctic infrastructure and ecosystems.', ex2_ko = '가속화되는 영구 동토층 해동이 북극 인프라와 생태계에 심각한 위협이 되고 있어요.',
  ex3 = 'Increasing wildfire frequency poses a growing threat to forests that serve as key carbon sinks.', ex3_ko = '증가하는 산불 빈도가 핵심 탄소 흡수원 역할을 하는 숲에 증가하는 위협이 되고 있어요.',
  ex4 = 'Intensifying tropical cyclones pose a severe threat to coastal populations and critical infrastructure.', ex4_ko = '강화되는 열대 사이클론이 해안 인구와 주요 인프라에 심각한 위협이 되고 있어요.',
  ex5 = 'Persistent ocean acidification poses a long-term threat to marine biodiversity and the fishing industry.', ex5_ko = '지속적인 해양 산성화가 해양 생물 다양성과 어업에 장기적인 위협이 되고 있어요.'
WHERE id = 's_weather_B2_06';

UPDATE sentences SET
  ex1 = 'Governments must implement ambitious policies to transition to a low-carbon economy.', ex1_ko = '정부들은 저탄소 경제로 전환하기 위한 야심찬 정책을 시행해야 해요.',
  ex2 = 'Governments must allocate sufficient funding to build resilient infrastructure against future climate impacts.', ex2_ko = '정부들은 미래 기후 영향에 대응하는 회복력 있는 인프라를 구축하기 위해 충분한 자금을 배정해야 해요.',
  ex3 = 'Governments must strengthen early warning systems to protect vulnerable communities from extreme weather events.', ex3_ko = '정부들은 극단적인 기상 현상으로부터 취약한 지역 사회를 보호하기 위해 조기 경보 시스템을 강화해야 해요.',
  ex4 = 'Governments must enforce stricter emissions standards across the transport and energy sectors.', ex4_ko = '정부들은 운송 및 에너지 부문 전반에 걸쳐 더 엄격한 배출 기준을 시행해야 해요.',
  ex5 = 'Governments must cooperate internationally to ensure that climate finance reaches the most vulnerable developing nations.', ex5_ko = '정부들은 기후 금융이 가장 취약한 개발 도상국에 전달되도록 국제적으로 협력해야 해요.'
WHERE id = 's_weather_B2_07';

UPDATE sentences SET
  ex1 = 'The stratospheric ozone depletion and its recovery illustrate how policy intervention can reverse environmental damage.', ex1_ko = '성층권 오존 감소와 그 회복은 정책 개입이 환경 피해를 되돌릴 수 있음을 보여줘요.',
  ex2 = 'The dramatic decline of acid rain and its reversal illustrate how targeted regulation can restore ecosystem health.', ex2_ko = '산성비의 극적인 감소와 그 회복은 목표화된 규제가 생태계 건강을 회복할 수 있음을 보여줘요.',
  ex3 = 'The collapse of certain fisheries and their partial recovery illustrate how removing human pressure can allow ecosystems to regenerate.', ex3_ko = '일부 어업의 붕괴와 부분적 회복은 인간의 압력 제거가 생태계를 재생시킬 수 있음을 보여줘요.',
  ex4 = 'The reduction in urban smog following stricter vehicle emission standards illustrates how technology mandates can improve air quality within years.', ex4_ko = '더 엄격한 차량 배출 기준 이후 도시 스모그 감소는 기술 의무화가 수년 내에 대기 질을 개선할 수 있음을 보여줘요.',
  ex5 = 'The recovery of several endangered bird species following habitat protection programmes illustrates how conservation investment can yield measurable ecological returns.', ex5_ko = '서식지 보호 프로그램 이후 일부 멸종 위기 조류 종의 회복은 보전 투자가 측정 가능한 생태적 성과를 낼 수 있음을 보여줘요.'
WHERE id = 's_weather_C1_01';

UPDATE sentences SET
  ex1 = 'The amplification of Arctic warming relative to the global average — often termed Arctic amplification — is accelerating permafrost thaw.', ex1_ko = '전 지구 평균 대비 북극 온난화 증폭 — 흔히 북극 증폭이라고 불리는 — 이 영구 동토층 해동을 가속화하고 있어요.',
  ex2 = 'The disproportionate warming of continental interiors relative to coastal regions — a recognised pattern in climate projections — is extending the fire season across boreal forests.', ex2_ko = '해안 지역 대비 대륙 내부의 불균형한 온난화 — 기후 전망에서 인정된 패턴 — 이 북방 숲 전역에 걸쳐 화재 시즌을 연장하고 있어요.',
  ex3 = 'The intensification of precipitation extremes relative to historical baselines — a robust projection across all major climate models — is overwhelming drainage infrastructure in rapidly urbanising regions.', ex3_ko = '역사적 기준 대비 강수 극단의 강화 — 모든 주요 기후 모델에 걸쳐 강건한 전망 — 이 빠르게 도시화되는 지역의 배수 인프라를 압도하고 있어요.',
  ex4 = 'The elevation of ocean heat content relative to pre-industrial levels — an indicator of long-term thermal energy accumulation — is intensifying tropical cyclone activity in all major ocean basins.', ex4_ko = '산업화 이전 수준 대비 해양 열 함량의 상승 — 장기 열에너지 축적의 지표 — 이 모든 주요 해양 분지에서 열대 사이클론 활동을 강화하고 있어요.',
  ex5 = 'The acceleration of sea level rise relative to the twentieth-century mean rate — now clearly attributable to anthropogenic forcing — is accelerating the erosion of low-lying coastal habitats worldwide.', ex5_ko = '20세기 평균 속도 대비 해수면 상승 가속화 — 이제 인위적 강제력에 명확히 귀인되는 — 이 전 세계적으로 저지대 해안 서식지 침식을 가속화하고 있어요.'
WHERE id = 's_weather_C1_02';

UPDATE sentences SET
  ex1 = 'Teleconnections such as El Niño have profound implications for agricultural planning across the globe.', ex1_ko = '엘니뇨 같은 원격 상관관계는 전 세계 농업 계획에 깊은 영향을 미쳐요.',
  ex2 = 'Teleconnections such as the Indian Ocean Dipole have profound implications for seasonal rainfall forecasting across East Africa and southern Asia.', ex2_ko = '인도양 쌍극자 같은 원격 상관관계는 동아프리카와 남부 아시아 전역의 계절적 강수 예보에 깊은 영향을 미쳐요.',
  ex3 = 'Teleconnections such as the North Atlantic Oscillation have profound implications for winter temperature and precipitation patterns across Europe and North America.', ex3_ko = '북대서양 진동 같은 원격 상관관계는 유럽과 북아메리카 전역의 겨울 기온 및 강수 패턴에 깊은 영향을 미쳐요.',
  ex4 = 'Teleconnections such as the Pacific Decadal Oscillation have profound implications for long-range drought forecasting in the western United States.', ex4_ko = '태평양 수십 년 진동 같은 원격 상관관계는 미국 서부의 장기 가뭄 예보에 깊은 영향을 미쳐요.',
  ex5 = 'Teleconnections such as the Arctic Oscillation have profound implications for the positioning of the polar jet stream and associated cold-air outbreaks.', ex5_ko = '북극 진동 같은 원격 상관관계는 극지 제트 기류의 위치와 관련된 한기 급습에 깊은 영향을 미쳐요.'
WHERE id = 's_weather_C1_03';

UPDATE sentences SET
  ex1 = 'Without significant reductions in radiative forcing, crossing multiple tipping points becomes increasingly probable.', ex1_ko = '복사 강제력의 상당한 감소 없이는 여러 티핑 포인트를 넘는 것이 점점 더 가능성이 높아져요.',
  ex2 = 'Without sustained investment in coastal defences, inundation of densely populated delta regions becomes increasingly probable within decades.', ex2_ko = '해안 방어에 대한 지속적인 투자 없이는 수십 년 내에 인구 밀집 삼각주 지역의 침수가 점점 더 가능성이 높아져요.',
  ex3 = 'Without rapid decarbonisation of the global energy system, limiting warming to 1.5 degrees becomes increasingly improbable.', ex3_ko = '전 지구적 에너지 시스템의 빠른 탈탄소화 없이는 온난화를 1.5도로 제한하는 것이 점점 더 가능성이 낮아져요.',
  ex4 = 'Without effective international coordination on methane reduction, achieving meaningful near-term climate benefits becomes increasingly difficult.', ex4_ko = '메탄 감축에 관한 효과적인 국제 조정 없이는 의미 있는 단기 기후 혜택 달성이 점점 더 어려워져요.',
  ex5 = 'Without comprehensive loss and damage finance mechanisms, adaptation in the most climate-vulnerable nations becomes increasingly untenable.', ex5_ko = '포괄적인 손실 및 피해 금융 메커니즘 없이는 기후 취약성이 가장 높은 국가들의 적응이 점점 더 지속 불가능해져요.'
WHERE id = 's_weather_C1_04';

UPDATE sentences SET
  ex1 = 'The thermohaline circulation is sensitive to freshwater input from melting ice sheets, which could disrupt heat distribution across the North Atlantic.', ex1_ko = '열염 순환은 녹는 빙상에서 유입되는 담수에 민감하여 북대서양 전역의 열 분배를 교란시킬 수 있어요.',
  ex2 = 'The global carbon cycle is sensitive to temperature increases, which could trigger additional CO₂ and methane release from natural reservoirs.', ex2_ko = '전 지구적 탄소 순환은 기온 상승에 민감하여 자연 저장소에서 CO₂와 메탄의 추가 방출을 촉발할 수 있어요.',
  ex3 = 'The West Antarctic Ice Sheet is sensitive to ocean warming beneath its base, which could accelerate marine ice sheet instability and raise sea levels faster than projected.', ex3_ko = '서남극 빙상은 기반부 아래의 해양 온난화에 민감하여 해양 빙상 불안정성을 가속화하고 해수면을 예측보다 빠르게 높일 수 있어요.',
  ex4 = 'The Asian monsoon system is sensitive to land-sea temperature contrasts, which could shift rainfall distribution across one of the world''s most densely populated regions.', ex4_ko = '아시아 몬순 시스템은 육해 기온 대비에 민감하여 세계에서 가장 인구 밀집한 지역의 강수 분포를 변화시킬 수 있어요.',
  ex5 = 'The Amazon rainforest is sensitive to reduced rainfall and increased fire frequency, which could push it past a dieback tipping point with global consequences.', ex5_ko = '아마존 열대우림은 강수량 감소와 화재 빈도 증가에 민감하여 전 지구적 결과를 가진 고사 티핑 포인트를 넘길 수 있어요.'
WHERE id = 's_weather_C1_05';

UPDATE sentences SET
  ex1 = 'Climate models project a poleward shift of storm tracks, altering precipitation patterns in mid-latitudes.', ex1_ko = '기후 모델은 폭풍 경로의 극지방 이동을 예측하여 중위도의 강수 패턴을 변화시켜요.',
  ex2 = 'Climate models project a significant increase in the intensity of the most extreme rainfall events, increasing flood risk in both urban and rural areas.', ex2_ko = '기후 모델은 가장 극단적인 강수 사태의 강도가 크게 증가하여 도시 및 농촌 지역 모두에서 홍수 위험을 높일 것으로 예측해요.',
  ex3 = 'Climate models project an expansion of arid and semi-arid climate zones, threatening water security across large swathes of the subtropics.', ex3_ko = '기후 모델은 건조 및 반건조 기후 지역이 확장되어 아열대 지역의 넓은 범위에 걸쳐 수자원 안보를 위협할 것으로 예측해요.',
  ex4 = 'Climate models project an increase in the frequency of compound weather extremes, such as simultaneous heatwaves and droughts.', ex4_ko = '기후 모델은 동시적 폭염과 가뭄 같은 복합 기상 극단의 빈도가 증가할 것으로 예측해요.',
  ex5 = 'Climate models project an amplification of the global water cycle, with wetter wet seasons and drier dry seasons becoming more pronounced.', ex5_ko = '기후 모델은 전 지구적 물 순환의 증폭으로 더 습한 우기와 더 건조한 건기가 더욱 두드러질 것으로 예측해요.'
WHERE id = 's_weather_C1_06';

UPDATE sentences SET
  ex1 = 'Robust attribution studies have established that the 2021 Pacific Northwest heat dome was virtually impossible without anthropogenic climate forcing.', ex1_ko = '강건한 귀인 연구들은 2021년 태평양 북서부 열돔이 인위적 기후 강제력 없이는 사실상 불가능했을 것이라고 밝혔어요.',
  ex2 = 'Robust attribution studies have established that the probability of extreme flooding events of this magnitude has at least doubled due to human-caused climate change.', ex2_ko = '강건한 귀인 연구들은 이 규모의 극단적 홍수 현상의 확률이 인간이 유발한 기후 변화로 인해 적어도 두 배 이상 높아졌다고 밝혔어요.',
  ex3 = 'Robust attribution studies have established that the record-breaking sea surface temperatures observed in 2023 were substantially influenced by anthropogenic greenhouse gas emissions.', ex3_ko = '강건한 귀인 연구들은 2023년에 관측된 기록적인 해수면 온도가 인위적 온실 가스 배출에 의해 상당히 영향받았다고 밝혔어요.',
  ex4 = 'Robust attribution studies have established that anthropogenic warming has already made coral bleaching events of this severity approximately five times more likely than in the pre-industrial climate.', ex4_ko = '강건한 귀인 연구들은 인위적 온난화가 이미 이 심각도의 산호 백화 현상을 산업화 이전 기후보다 약 5배 더 가능성 있게 만들었다고 밝혔어요.',
  ex5 = 'Robust attribution studies have established that the unprecedented glacier mass loss observed in recent decades cannot be explained by natural variability alone.', ex5_ko = '강건한 귀인 연구들은 최근 수십 년간 관측된 전례 없는 빙하 질량 손실이 자연 변동성만으로는 설명될 수 없다고 밝혔어요.'
WHERE id = 's_weather_C1_07';

UPDATE sentences SET
  ex1 = 'Paleoclimatological proxies, including ice cores and dendrochronological records, reveal that current warming rates are anomalous relative to any comparable interval in the Holocene.', ex1_ko = '얼음 코어와 연륜연대학 기록을 포함한 고기후학적 대리 기록들은 현재의 온난화 속도가 홀로세의 어떤 비교 가능한 기간에 비해서도 이상하다는 것을 드러내요.',
  ex2 = 'Paleoclimatological proxies, including stalagmite records and marine sediment cores, reveal that abrupt climate transitions have occurred repeatedly throughout Earth''s history on timescales of decades rather than millennia.', ex2_ko = '석순 기록과 해양 퇴적물 코어를 포함한 고기후학적 대리 기록들은 지구 역사를 통해 급격한 기후 전환이 수천 년이 아닌 수십 년의 시간 규모로 반복적으로 발생했음을 드러내요.',
  ex3 = 'Paleoclimatological proxies, including pollen assemblages and lake sediment records, reveal that past shifts in the monsoon system dramatically reorganised vegetation belts across entire continents.', ex3_ko = '꽃가루 집합체와 호수 퇴적물 기록을 포함한 고기후학적 대리 기록들은 몬순 시스템의 과거 변화가 대륙 전체에 걸쳐 식생 지대를 극적으로 재편했음을 드러내요.',
  ex4 = 'Paleoclimatological proxies, including boreholes and coral archives, reveal that the rate of sea level rise projected for the coming century would be extraordinary in the context of the late Quaternary.', ex4_ko = '시추공과 산호 기록을 포함한 고기후학적 대리 기록들은 다가오는 세기에 예상되는 해수면 상승 속도가 후기 제4기의 맥락에서 특별하다는 것을 드러내요.',
  ex5 = 'Paleoclimatological proxies, including varved sediments and speleothems, reveal that intervals of rapid CO₂ change in Earth''s past were closely coupled with large-scale reorganisations of the global carbon cycle.', ex5_ko = '엽층 퇴적물과 동굴생성물을 포함한 고기후학적 대리 기록들은 지구 과거의 빠른 CO₂ 변화 구간이 전 지구적 탄소 순환의 대규모 재편과 밀접하게 결합되어 있었음을 드러내요.'
WHERE id = 's_weather_C2_01';

UPDATE sentences SET
  ex1 = 'The biogeochemical feedbacks triggered by permafrost degradation — notably the release of previously sequestered methane and CO₂ — could render current emission reduction targets insufficient.', ex1_ko = '영구 동토층 분해에 의해 촉발된 생지화학적 피드백 — 특히 이전에 격리된 메탄과 CO₂의 방출 — 이 현재 배출 감축 목표를 불충분하게 만들 수 있어요.',
  ex2 = 'The hydrological feedbacks amplified by reduced land surface moisture — particularly the increase in sensible versus latent heat flux — could render current drought frequency projections a significant underestimate.', ex2_ko = '육지 표면 수분 감소에 의해 증폭된 수문 피드백 — 특히 잠열 유속 대비 현열 유속의 증가 — 이 현재 가뭄 빈도 전망을 크게 과소 추정하게 만들 수 있어요.',
  ex3 = 'The albedo feedbacks associated with Arctic sea ice loss — principally the replacement of high-reflectivity ice by low-reflectivity open ocean — could render Arctic temperature projections based on earlier models substantially conservative.', ex3_ko = '북극 해빙 손실과 관련된 알베도 피드백 — 주로 높은 반사율의 얼음이 낮은 반사율의 열린 바다로 대체되는 것 — 이 이전 모델에 기반한 북극 기온 전망을 상당히 보수적으로 만들 수 있어요.',
  ex4 = 'The ecosystem feedbacks initiated by large-scale deforestation — especially the reduction in evapotranspiration and associated rainfall recycling — could render regional water availability projections in tropical areas increasingly unreliable.', ex4_ko = '대규모 삼림 벌채에 의해 시작된 생태계 피드백 — 특히 증발산 감소와 관련된 강수 재활용 — 이 열대 지역의 지역 수자원 가용성 전망을 점점 더 신뢰할 수 없게 만들 수 있어요.',
  ex5 = 'The cloud feedback uncertainties arising from changes in low cloud cover — particularly in the subtropical marine boundary layer — could render the lower end of equilibrium climate sensitivity estimates implausibly optimistic.', ex5_ko = '하층 구름 덮개 변화에서 발생하는 구름 피드백 불확실성 — 특히 아열대 해양 경계층에서 — 이 평형 기후 민감도 추정의 하한을 비현실적으로 낙관적으로 만들 수 있어요.'
WHERE id = 's_weather_C2_02';

UPDATE sentences SET
  ex1 = 'Disentangling natural climate variability from anthropogenic forcing requires sophisticated attribution methodologies that account for the full breadth of internal climate oscillations.', ex1_ko = '자연 기후 변동성과 인위적 강제력을 분리하려면 내부 기후 진동의 전체 범위를 고려하는 정교한 귀인 방법론이 필요해요.',
  ex2 = 'Disentangling volcanic signals from greenhouse gas forcing in the temperature record requires statistical techniques that isolate episodic aerosol perturbations from the long-term warming trend.', ex2_ko = '기온 기록에서 화산 신호와 온실 가스 강제력을 분리하려면 장기 온난화 추세에서 간헐적 에어로졸 교란을 분리하는 통계 기술이 필요해요.',
  ex3 = 'Disentangling orbital forcing from internal feedbacks in paleoclimate records requires high-resolution proxy datasets that resolve centennial-scale climate variability.', ex3_ko = '고기후 기록에서 궤도 강제력과 내부 피드백을 분리하려면 백 년 규모의 기후 변동성을 해소하는 고해상도 대리 데이터셋이 필요해요.',
  ex4 = 'Disentangling land-use change signals from greenhouse gas-driven warming in regional temperature trends requires carefully constructed model experiments that isolate each forcing factor independently.', ex4_ko = '지역 기온 추세에서 토지 이용 변화 신호와 온실 가스 유발 온난화를 분리하려면 각 강제력 요인을 독립적으로 분리하는 신중하게 구성된 모델 실험이 필요해요.',
  ex5 = 'Disentangling aerosol effects on precipitation from thermodynamic intensification of the water cycle requires coordinated observational and modelling strategies that span multiple spatial scales.', ex5_ko = '물 순환의 열역학적 강화로부터 강수에 대한 에어로졸 효과를 분리하려면 여러 공간 규모에 걸친 협력적인 관측 및 모델링 전략이 필요해요.'
WHERE id = 's_weather_C2_03';

UPDATE sentences SET
  ex1 = 'The convergence of thermohaline circulation weakening, sea ice albedo feedback, and permafrost carbon release represents a compound risk that integrated assessment models may systematically underestimate.', ex1_ko = '열염 순환 약화, 해빙 알베도 피드백, 영구 동토층 탄소 방출의 수렴은 통합 평가 모델이 체계적으로 과소 추정할 수 있는 복합 위험을 나타내요.',
  ex2 = 'The convergence of sea level rise, intensified storm surge, and coastal infrastructure degradation represents a compound risk to densely populated delta regions that current adaptation planning may insufficiently address.', ex2_ko = '해수면 상승, 강화된 폭풍 해일, 해안 인프라 열화의 수렴은 현재 적응 계획이 불충분하게 다룰 수 있는 인구 밀집 삼각주 지역에 복합 위험을 나타내요.',
  ex3 = 'The convergence of prolonged drought, elevated fire risk, and biodiversity loss in Mediterranean climate zones represents a compound ecosystem stress that may accelerate irreversible regime shifts.', ex3_ko = '지중해 기후대에서 장기 가뭄, 높아진 화재 위험, 생물 다양성 손실의 수렴은 비가역적인 체제 전환을 가속화할 수 있는 복합 생태계 스트레스를 나타내요.',
  ex4 = 'The convergence of reduced snowpack, earlier snowmelt, and increased summer evapotranspiration represents a compound water stress that threatens agricultural viability across many semi-arid mountain watersheds.', ex4_ko = '감소한 적설량, 이른 적설 용해, 증가한 여름 증발산의 수렴은 많은 반건조 산악 유역에 걸쳐 농업 경제성을 위협하는 복합 수분 스트레스를 나타내요.',
  ex5 = 'The convergence of ocean acidification, coral bleaching, and coastal eutrophication represents a compound threat to reef ecosystems that exceeds the adaptive capacity of most coral species.', ex5_ko = '해양 산성화, 산호 백화, 해안 부영양화의 수렴은 대부분 산호 종의 적응 능력을 초과하는 암초 생태계에 대한 복합 위협을 나타내요.'
WHERE id = 's_weather_C2_04';

UPDATE sentences SET
  ex1 = 'Dendroclimatological reconstructions corroborate instrumentally derived temperature anomalies, lending credibility to projections that current forcing trajectories will breach Holocene temperature bounds within decades.', ex1_ko = '연륜기후학적 재구성이 기기로 도출된 기온 편차를 뒷받침하여 현재 강제력 궤도가 수십 년 내에 홀로세 기온 한계를 넘을 것이라는 전망에 신뢰성을 더해요.',
  ex2 = 'Speleothem records corroborate monsoon intensity reconstructions from pollen archives, lending credibility to projections that future warming will substantially reorganise tropical precipitation belts.', ex2_ko = '동굴생성물 기록이 꽃가루 기록의 몬순 강도 재구성을 뒷받침하여 미래 온난화가 열대 강수대를 상당히 재편할 것이라는 전망에 신뢰성을 더해요.',
  ex3 = 'Coral proxy records corroborate satellite-era sea surface temperature trends, lending credibility to projections that coral reef systems face existential stress under even moderate emissions trajectories.', ex3_ko = '산호 대리 기록이 위성 시대 해수면 온도 추세를 뒷받침하여 산호 암초 시스템이 온건한 배출 궤도에서도 실존적 스트레스에 직면할 것이라는 전망에 신뢰성을 더해요.',
  ex4 = 'Marine sediment records corroborate terrestrial evidence of widespread megadroughts, lending credibility to projections that regional hydroclimate variability will increase substantially under higher forcing scenarios.', ex4_ko = '해양 퇴적물 기록이 광범위한 거대 가뭄의 육상 증거를 뒷받침하여 높은 강제력 시나리오에서 지역 수문기후 변동성이 크게 증가할 것이라는 전망에 신뢰성을 더해요.',
  ex5 = 'Pollen-based climate reconstructions corroborate model simulations of the Holocene Thermal Maximum, lending credibility to projections that ongoing warming will eventually push global temperatures beyond any analogue in the last ten thousand years.', ex5_ko = '꽃가루 기반 기후 재구성이 홀로세 열적 극대기의 모델 시뮬레이션을 뒷받침하여 진행 중인 온난화가 결국 전 지구 기온을 지난 1만 년간의 어떤 유사체도 넘어서게 할 것이라는 전망에 신뢰성을 더해요.'
WHERE id = 's_weather_C2_05';

UPDATE sentences SET
  ex1 = 'Radiative forcing from short-lived climate pollutants, particularly black carbon and tropospheric ozone, constitutes a non-trivial fraction of total anthropogenic warming that near-term mitigation could rapidly reverse.', ex1_ko = '단기 기후 오염 물질, 특히 블랙 카본과 대류권 오존으로부터의 복사 강제력은 근기간 완화가 빠르게 되돌릴 수 있는 전체 인위적 온난화의 무시할 수 없는 부분을 구성해요.',
  ex2 = 'Land-use change forcing from tropical deforestation, particularly the loss of evapotranspiration and surface albedo modification, constitutes an underappreciated contribution to regional climate change that reforestation policies could significantly offset.', ex2_ko = '열대 삼림 벌채로부터의 토지 이용 변화 강제력, 특히 증발산 손실과 지표면 알베도 수정은 산림 재조성 정책이 크게 상쇄할 수 있는 지역 기후 변화에 대한 과소 평가된 기여를 구성해요.',
  ex3 = 'Ozone forcing from stratospheric ozone depletion, particularly over the Southern Ocean, constitutes a significant perturbation to Southern Hemisphere circulation patterns that recovery of the ozone layer is beginning to reverse.', ex3_ko = '성층권 오존 감소, 특히 남극해 위에서의, 로부터의 오존 강제력은 오존층 회복이 되돌리기 시작하고 있는 남반구 순환 패턴에 대한 상당한 교란을 구성해요.',
  ex4 = 'Agricultural methane and nitrous oxide forcing from livestock and fertiliser use, collectively constituting around a tenth of total greenhouse gas emissions, represents an area where targeted dietary and farming practice changes could deliver disproportionate climate benefits.', ex4_ko = '가축과 비료 사용으로부터의 농업 메탄과 아산화질소 강제력은 전체 온실 가스 배출량의 약 10분의 1을 구성하며 목표화된 식이 및 농업 관행 변화가 불균형적인 기후 혜택을 제공할 수 있는 영역을 나타내요.',
  ex5 = 'Volcanic sulphate aerosol forcing from large explosive eruptions, while inherently transient, constitutes a natural experiment in solar radiation management that climate scientists have used to validate feedback parameterisations in Earth system models.', ex5_ko = '대규모 폭발적 분화로부터의 화산 황산염 에어로졸 강제력은 본질적으로 일시적이지만, 기후 과학자들이 지구 시스템 모델의 피드백 매개변수화를 검증하는 데 사용해 온 태양 복사 관리의 자연 실험을 구성해요.'
WHERE id = 's_weather_C2_06';

UPDATE sentences SET
  ex1 = 'The epistemological challenge of projecting abrupt, threshold-crossing climate transitions lies in the inherently nonlinear dynamics of Earth system feedbacks, which resist reliable quantification within current modelling frameworks.', ex1_ko = '급격한 임계값 초과 기후 전환을 예측하는 인식론적 과제는 현재 모델링 프레임워크 내에서 신뢰할 수 있는 정량화에 저항하는, 지구 시스템 피드백의 본질적으로 비선형적인 역학에 있어요.',
  ex2 = 'The epistemological challenge of constraining long-tail climate risk lies in the fundamental difficulty of empirically characterising low-probability, high-consequence events within the relatively short instrumental record.', ex2_ko = '장미 꼬리 기후 위험을 제약하는 인식론적 과제는 비교적 짧은 기기 기록 내에서 낮은 확률, 높은 결과의 사태를 경험적으로 특성화하는 근본적인 어려움에 있어요.',
  ex3 = 'The epistemological challenge of evaluating solar geoengineering proposals lies in the impossibility of conducting controlled planetary-scale experiments, which forces reliance on modelling studies whose validity cannot be verified empirically.', ex3_ko = '태양 지구공학 제안을 평가하는 인식론적 과제는 경험적으로 유효성을 검증할 수 없는 모델링 연구에 의존할 수밖에 없게 하는, 통제된 행성 규모 실험 수행의 불가능성에 있어요.',
  ex4 = 'The epistemological challenge of attributing changes in regional precipitation trends to anthropogenic forcing lies in the high natural variability of rainfall, which can mask forced signals even over multi-decadal averaging periods.', ex4_ko = '지역 강수 추세의 변화를 인위적 강제력에 귀인하는 인식론적 과제는 수십 년 평균 기간에도 강제력 신호를 감출 수 있는 강수의 높은 자연 변동성에 있어요.',
  ex5 = 'The epistemological challenge of integrating deep-time paleoclimate evidence into near-term projections lies in the vast differences in boundary conditions, forcings, and system states between past warm climates and the anthropogenically perturbed present.', ex5_ko = '심층 시간 고기후 증거를 단기 전망에 통합하는 인식론적 과제는 과거 온난 기후와 인위적으로 교란된 현재 사이의 경계 조건, 강제력, 시스템 상태에서의 방대한 차이에 있어요.'
WHERE id = 's_weather_C2_07';
